static inline marmot_qscheme_id_t marmot_string_to_qscheme_id(const char *name) {
    if (name == nullptr) {
        return MARMOT_QSCHEME_NONE;
    }
    if (strcmp(name, "NONE") == 0) {
        return MARMOT_QSCHEME_NONE;
    }
    if (strcmp(name, "Q4_0") == 0) {
        return MARMOT_QSCHEME_Q4_0;
    }
    if (strcmp(name, "Q4_1") == 0) {
        return MARMOT_QSCHEME_Q4_1;
    }
    if (strcmp(name, "Q5_0") == 0) {
        return MARMOT_QSCHEME_Q5_0;
    }
    if (strcmp(name, "Q5_1") == 0) {
        return MARMOT_QSCHEME_Q5_1;
    }
    if (strcmp(name, "Q8_0") == 0) {
        return MARMOT_QSCHEME_Q8_0;
    }
    if (strcmp(name, "Q2_K") == 0) {
        return MARMOT_QSCHEME_Q2_K;
    }
    if (strcmp(name, "Q3_K") == 0) {
        return MARMOT_QSCHEME_Q3_K;
    }
    if (strcmp(name, "Q4_K") == 0) {
        return MARMOT_QSCHEME_Q4_K;
    }
    if (strcmp(name, "Q5_K") == 0) {
        return MARMOT_QSCHEME_Q5_K;
    }
    if (strcmp(name, "Q6_K") == 0) {
        return MARMOT_QSCHEME_Q6_K;
    }
    if (strcmp(name, "Q8_K") == 0) {
        return MARMOT_QSCHEME_Q8_K;
    }
    if (strcmp(name, "Q8_1") == 0) {
        return MARMOT_QSCHEME_Q8_1;
    }
    return MARMOT_QSCHEME_NONE;
}

